from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about a mean of transportation into one fluent,
    natural‑language sentence.  Predicates are rendered with small, readable
    phrasing and subsequent triples are attached as relative clauses.
    """
    if not triples:
        return ""

    # Helper to turn a single triple into a clause fragment.
    def render(t: Triple, is_first: bool) -> str:
        pred = t.predicate
        obj = t.object

        # Specific, more natural renderings for common predicates
        if pred == "alternativeName":
            fragment = f"also known as {obj}"
        elif pred == "manufacturer":
            fragment = f"manufactured by {obj}"
        elif pred == "builder":
            fragment = f"built by {obj}"
        elif pred == "owner":
            fragment = f"owned by {obj}"
        elif pred == "operator":
            fragment = f"operated by {obj}"
        elif pred == "parentCompany":
            fragment = f"a subsidiary of {obj}"
        elif pred == "relatedMeanOfTransportation":
            fragment = f"related to {obj}"
        elif pred == "engine":
            fragment = f"powered by {obj}"
        elif pred == "transmission":
            fragment = f"with a {obj} transmission"
        elif pred == "wheelbase":
            fragment = f"having a wheelbase of {obj}"
        elif pred == "length":
            fragment = f"measuring {obj} in length"
        elif pred == "shipPower":
            fragment = f"equipped with {obj}"
        elif pred == "topSpeed":
            fragment = f"capable of reaching {obj} knots"
        else:
            # Generic fallback – turn predicate into readable phrase
            readable = pred.replace("_", " ")
            fragment = f"has {readable} {obj}"

        # First clause includes the subject; later clauses become relative clauses
        return f"{t.subject} {fragment}" if is_first else fragment

    # Build the sentence
    first_clause = render(triples[0], True)
    if len(triples) == 1:
        sentence = first_clause
    else:
        # Subsequent clauses are added as comma‑separated relative clauses
        rest = ", ".join(render(t, False) for t in triples[1:])
        sentence = f"{first_clause}, {rest}"

    return sentence + "."

# EVOLVE-BLOCK-END

